        start_window, end_window = time_windows[i]
        if arrival_time < start_window:
            time_penalty = (start_window - arrival_time)**2  # square penalty for early arrival
        elif arrival_time > end_window:
            time_penalty = (arrival_time - end_window)**2 * 10  # square penalty for late, scaled up
        else:
            time_penalty = 0  # no penalty if in the time window

        collaborative_penalty = 0
        for other_truck_pos in all_truck_pos:
