    all_truck_pos_without_current = [pos for pos in all_truck_pos if not np.array_equal(pos, cur_truck_pos)]

    efficiency_scores = [calculate_efficiency_score(customer, time_windows[i], all_truck_pos_without_current)
                         for i, customer in enumerate(unvisited_customers)]

